import { useState, useEffect } from 'react';
import { countWords, countCharacters, convertToUpperCase, convertToLowerCase, cleanWhitespace } from '../utils/textProcessing';

const useTextAnalysis = (inputText) => {
    const [wordCount, setWordCount] = useState(0);
    const [characterCount, setCharacterCount] = useState(0);
    const [cleanedText, setCleanedText] = useState('');

    useEffect(() => {
        const words = countWords(inputText);
        const characters = countCharacters(inputText);
        setWordCount(words);
        setCharacterCount(characters);
        setCleanedText(inputText);
    }, [inputText]);

    const toUpperCase = () => {
        setCleanedText(convertToUpperCase(cleanedText));
    };

    const toLowerCase = () => {
        setCleanedText(convertToLowerCase(cleanedText));
    };

    const cleanupWhitespace = () => {
        setCleanedText(cleanWhitespace(cleanedText));
    };

    return {
        wordCount,
        characterCount,
        cleanedText,
        toUpperCase,
        toLowerCase,
        cleanupWhitespace,
    };
};

export default useTextAnalysis;
